"use client"

import type React from "react"
import { createContext, useContext, useState, useEffect, useCallback } from "react"
import { createClient } from "@/lib/supabase/client"

interface UserProfile {
  id?: string
  user_id?: string
  age?: number | string | null
  sex?: string | null
  ethnicity?: string | null
  height?: string | null
  weight?: string | null
  lifestyle?: {
    exercise?: string | null
    diet?: string | null
    smoking?: string | null
    alcohol?: string | null
    sleep?: string | null
    stress?: string | null
  }
  medications?: string[]
  medical_conditions?: string[]
}

interface User {
  id: string
  email: string
  user_metadata?: any
  profile?: UserProfile
}

interface AuthContextType {
  user: User | null
  isAuthenticated: boolean
  login: (email: string, password: string) => Promise<boolean>
  signup: (email: string, password: string) => Promise<boolean>
  logout: () => void
  loading: boolean
  error: string | null
  updateProfile: (profileData: UserProfile) => Promise<boolean>
  loadProfile: () => Promise<void>
  profileLoaded: boolean
}

const AuthContext = createContext<AuthContextType | undefined>(undefined)

export function AuthProvider({ children }: { children: React.ReactNode }) {
  const [user, setUser] = useState<User | null>(null)
  const [isAuthenticated, setIsAuthenticated] = useState(false)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [supabase, setSupabase] = useState<any>(null)
  const [profileLoaded, setProfileLoaded] = useState(false)
  const [profileLoadAttempts, setProfileLoadAttempts] = useState(0)

  useEffect(() => {
    try {
      // Check if required environment variables are available
      if (!process.env.NEXT_PUBLIC_SUPABASE_URL || !process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY) {
        console.warn("[v0] Supabase environment variables not found, running in offline mode")
        setLoading(false)
        return
      }

      const client = createClient()
      setSupabase(client)
      console.log("[v0] Supabase client created successfully")
    } catch (err) {
      console.error("[v0] Failed to create Supabase client:", err)
      setError("Authentication service unavailable")
      setLoading(false)
      return
    }
  }, [])

  useEffect(() => {
    if (!supabase) return

    const getSession = async () => {
      try {
        const {
          data: { session },
        } = await supabase.auth.getSession()

        if (session?.user) {
          const userData = {
            id: session.user.id,
            email: session.user.email!,
            user_metadata: session.user.user_metadata,
          }
          setUser(userData)
          setIsAuthenticated(true)
        }
        setError(null)
      } catch (err) {
        console.error("Failed to get session:", err)
        setError("Failed to get session")
      } finally {
        setLoading(false)
      }
    }

    getSession()

    const {
      data: { subscription },
    } = supabase.auth.onAuthStateChange(async (event: any, session: any) => {
      try {
        if (session?.user) {
          setUser((prevUser) => {
            const userData = {
              id: session.user.id,
              email: session.user.email!,
              user_metadata: session.user.user_metadata,
              // Preserve existing profile if it exists
              profile: prevUser?.profile,
            }
            return userData
          })
          setIsAuthenticated(true)
          setProfileLoaded(false) // Reset profile loaded flag for new user
          setProfileLoadAttempts(0) // Reset attempts for new user

          // Check for pending results when user becomes authenticated
          if (event === 'SIGNED_IN' || event === 'TOKEN_REFRESHED') {
            savePendingResults()
          }
        } else {
          setUser(null)
          setIsAuthenticated(false)
          setProfileLoaded(false)
          setProfileLoadAttempts(0)
        }
        setError(null)
      } catch (err) {
        console.error("Auth state change error:", err)
        setError("Authentication error")
      }
      setLoading(false)
    })

    return () => subscription.unsubscribe()
  }, [supabase])

  const savePendingResults = useCallback(async () => {
    try {
      // Check if we're in browser environment and have pending results
      if (typeof window !== 'undefined' && window.localStorage) {
        const pendingResults = localStorage.getItem("kml_pending_results")
        const saveAttempted = localStorage.getItem("kml_save_attempted")

        if (pendingResults && !saveAttempted) {
          console.log("[Auth Context] Found pending results, attempting to save...")

          // Mark that we've attempted to save to prevent multiple calls
          localStorage.setItem("kml_save_attempted", "true")

          const resultsData = JSON.parse(pendingResults)

          const response = await fetch("/api/save-pending-results", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
            },
            body: JSON.stringify(resultsData),
          })

          if (response.ok) {
            const result = await response.json()
            if (result.success) {
              console.log("[Auth Context] Pending results saved successfully")
              // Clear the pending results and save attempt flag from localStorage
              localStorage.removeItem("kml_pending_results")
              localStorage.removeItem("kml_save_attempted")
            } else {
              console.error("[Auth Context] Failed to save pending results:", result.message)
              // Remove the save attempt flag so we can try again
              localStorage.removeItem("kml_save_attempted")
            }
          } else {
            console.error("[Auth Context] Failed to save pending results:", response.statusText)
            // Remove the save attempt flag so we can try again
            localStorage.removeItem("kml_save_attempted")
          }
        } else if (saveAttempted) {
          console.log("[Auth Context] Save already attempted, skipping...")
        }
      }
    } catch (error) {
      console.error("[Auth Context] Error saving pending results:", error)
      // Remove the save attempt flag so we can try again
      if (typeof window !== 'undefined' && window.localStorage) {
        localStorage.removeItem("kml_save_attempted")
      }
    }
  }, [])

  useEffect(() => {
    if (user?.id && isAuthenticated && supabase && !profileLoaded && profileLoadAttempts < 3) {
      loadProfile()
    }

    // Check for pending results when user is authenticated (for page refreshes)
    if (user?.id && isAuthenticated && !loading) {
      console.log("[Auth Context] useEffect triggered - checking for pending results")
      savePendingResults()
    }
  }, [user?.id, isAuthenticated, supabase, profileLoaded, profileLoadAttempts, loading, savePendingResults])

  const loadProfile = async () => {
    console.log("[Auth Context] loadProfile called, profileLoaded:", profileLoaded, "attempts:", profileLoadAttempts)
    console.log("[Auth Context] User ID:", user?.id)
    console.log("[Auth Context] Supabase available:", !!supabase)
    setProfileLoadAttempts(prev => prev + 1)

    // Offline fallback: load from localStorage when Supabase is not configured
    if (!supabase) {
      try {
        // Check if we're in browser environment
        if (typeof window !== 'undefined' && window.localStorage) {
          const raw = localStorage.getItem("kml_profile")
          console.log("[Auth Context] localStorage profile data:", raw)
          if (raw) {
            const stored = JSON.parse(raw)
            console.log("[Auth Context] Parsed profile data:", stored)
            setUser((prev) => (prev ? { ...prev, profile: stored } : prev))
          } else {
            console.log("[Auth Context] No profile data found in localStorage")
          }
        }
        setProfileLoaded(true)
      } catch (err) {
        console.warn("[Auth Context] Failed to read local profile fallback:", err)
        setProfileLoaded(true)
      }
      return
    }

    if (!user?.id) return

    try {
      console.log("[v0] Loading profile for user:", user.id)

      const { data, error } = await supabase.from("user_profiles").select("*").eq("user_id", user.id).single()

      console.log("[v0] Profile query result:", { data, error })

      if (error) {
        if (error.code === "PGRST116") {
          // No rows returned - this is fine, user just doesn't have a profile yet
          console.log("[Auth Context] No profile found for user, this is normal for new users")
          setProfileLoaded(true)
          return
        } else {
          console.error("[Auth Context] Error loading profile:", error.message)
          setProfileLoaded(true)
          return
        }
      }

      if (data) {
        console.log("[Auth Context] Profile loaded successfully:", data)
        setUser((prev) => (prev ? { ...prev, profile: data } : null))
      }
      setProfileLoaded(true)
    } catch (err) {
      console.error("[Auth Context] Failed to load profile:", err)
      setProfileLoaded(true)
    }
  }

  const updateProfile = async (profileData: UserProfile): Promise<boolean> => {
    console.log("[Auth Context] updateProfile called with:", profileData)
    console.log("[Auth Context] Supabase available:", !!supabase)
    console.log("[Auth Context] User ID:", user?.id)
    console.log("[Auth Context] Is authenticated:", isAuthenticated)

    // Offline fallback: persist to localStorage when Supabase is not configured
    if (!supabase) {
      try {
        console.log("[Auth Context] Using localStorage fallback for profile save")

        // Check if we're in browser environment
        if (typeof window !== 'undefined' && window.localStorage) {
          localStorage.setItem("kml_profile", JSON.stringify({ ...profileData }))
          setUser((prev) => (prev ? { ...prev, profile: { ...profileData } } : prev))
          setError(null)
          console.log("[Auth Context] Profile saved to localStorage successfully")
          return true
        } else {
          console.error("[Auth Context] localStorage not available (server-side rendering)")
          setError("Cannot save profile - localStorage not available")
          return false
        }
      } catch (err) {
        console.error("[Auth Context] Local profile save failed:", err)
        setError("Failed to save profile locally")
        return false
      }
    }

    if (!user?.id) return false

    // Check Supabase session
    try {
      const { data: { session }, error: sessionError } = await supabase.auth.getSession()
      console.log("[Auth Context] Supabase session:", session ? "exists" : "none", sessionError)

      if (sessionError || !session) {
        console.error("[Auth Context] No valid Supabase session:", sessionError)
        console.log("[Auth Context] Falling back to localStorage save")

        // Fallback to localStorage when Supabase session is invalid
        try {
          if (typeof window !== 'undefined' && window.localStorage) {
            localStorage.setItem("kml_profile", JSON.stringify({ ...profileData }))
            setUser((prev) => (prev ? { ...prev, profile: { ...profileData } } : prev))
            setError(null)
            console.log("[Auth Context] Profile saved to localStorage as fallback")
            return true
          }
        } catch (err) {
          console.error("[Auth Context] localStorage fallback failed:", err)
        }

        setError("Authentication required - please sign in again")
        return false
      }
    } catch (err) {
      console.error("[Auth Context] Session check failed:", err)
      setError("Authentication check failed")
      return false
    }

    try {
      console.log("[v0] Updating profile for user:", user.id, profileData)

      const { data: existingProfile } = await supabase
        .from("user_profiles")
        .select("id")
        .eq("user_id", user.id)
        .single()

      let error
      if (existingProfile) {
        // Profile exists, use UPDATE
        const result = await supabase
          .from("user_profiles")
          .update({
            age: profileData.age,
            sex: profileData.sex,
            ethnicity: profileData.ethnicity,
            height: profileData.height,
            weight: profileData.weight,
            lifestyle: profileData.lifestyle || {},
            medications: profileData.medications || [],
            medical_conditions: profileData.medical_conditions || [],
          })
          .eq("user_id", user.id)

        error = result.error
      } else {
        // Profile doesn't exist, use INSERT
        const result = await supabase.from("user_profiles").insert({
          user_id: user.id,
          age: profileData.age,
          sex: profileData.sex,
          ethnicity: profileData.ethnicity,
          height: profileData.height,
          weight: profileData.weight,
          lifestyle: profileData.lifestyle || {},
          medications: profileData.medications || [],
          medical_conditions: profileData.medical_conditions || [],
        })

        error = result.error
      }

      if (error) {
        console.error("Error updating profile:", error)

        // If it's an RLS policy violation, fall back to localStorage
        if (error.code === '42501' || error.message.includes('row-level security')) {
          console.log("[Auth Context] RLS policy violation, falling back to localStorage")
          try {
            if (typeof window !== 'undefined' && window.localStorage) {
              localStorage.setItem("kml_profile", JSON.stringify({ ...profileData }))
              setUser((prev) => (prev ? { ...prev, profile: { ...profileData } } : prev))
              setError(null)
              console.log("[Auth Context] Profile saved to localStorage due to RLS policy")
              return true
            }
          } catch (err) {
            console.error("[Auth Context] localStorage fallback failed:", err)
          }
        }

        setError(error.message)
        return false
      }

      console.log("[v0] Profile updated successfully, reloading...")

      setUser((prev) =>
        prev
          ? {
              ...prev,
              profile: {
                ...profileData,
                user_id: user.id,
              },
            }
          : null,
      )

      await loadProfile()
      setError(null)

      console.log("[v0] Profile state updated")
      return true
    } catch (err) {
      console.error("Failed to update profile:", err)
      setError("Failed to update profile")
      return false
    }
  }

  const login = async (email: string, password: string): Promise<boolean> => {
    if (!supabase) return false

    try {
      const { error } = await supabase.auth.signInWithPassword({
        email,
        password,
      })

      if (error) {
        console.error("Login error:", error.message)
        setError(error.message)
        return false
      }

      setError(null)

      // Check for pending results and save them
      await savePendingResults()

      return true
    } catch (error) {
      console.error("Login error:", error)
      setError("Failed to sign in")
      return false
    }
  }

  const signup = async (email: string, password: string): Promise<boolean> => {
    if (!supabase) return false

    try {
      const { error } = await supabase.auth.signUp({
        email,
        password,
        options: {
          emailRedirectTo: process.env.NEXT_PUBLIC_DEV_SUPABASE_REDIRECT_URL || `${window.location.origin}/dashboard`,
        },
      })

      if (error) {
        console.error("Signup error:", error.message)
        setError(error.message)
        return false
      }

      setError(null)
      return true
    } catch (error) {
      console.error("Signup error:", error)
      setError("Failed to sign up")
      return false
    }
  }


  const logout = async () => {
    if (!supabase) return

    try {
      await supabase.auth.signOut()
      setError(null)
    } catch (error) {
      console.error("Logout error:", error)
      setError("Failed to sign out")
    }
  }

  return (
    <AuthContext.Provider
      value={{
        user,
        isAuthenticated,
        login,
        signup,
        logout,
        loading,
        error,
        updateProfile,
        loadProfile,
        profileLoaded,
      }}
    >
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const context = useContext(AuthContext)
  if (context === undefined) {
    throw new Error("useAuth must be used within an AuthProvider")
  }
  return context
}

