import { NextRequest, NextResponse } from 'next/server';
import { createClient } from '@/lib/supabase/server';
import { 
  redactDataForClient, 
  createDeIdentifiedData, 
  hasConsentForStorage,
  DEFAULT_CONFIG 
} from '@/lib/server-redaction';

// This is needed for App Router
export const dynamic = 'force-dynamic';

interface ProcessCompleteRequest {
  demographics: {
    age: number;
    sex: string;
    height?: number;
    weight?: number;
    pregnant?: boolean;
    medical_conditions?: string[];
    medications?: string[];
  };
  context?: {
    reason: string;
    symptoms: string[];
    concerns: string[];
  };
  labs: Array<{
    code: string;
    name: string;
    value: number;
    unit: string;
    value_si: number;
    unit_si: string;
    ref_range_low?: number;
    ref_range_high?: number;
    category?: string;
  }>;
  consent?: {
    consent: boolean;
    timestamp: string;
  };
  updateExistingLabSetId?: string; // If provided, update existing lab set instead of creating new one
}

interface ProcessCompleteResponse {
  success: boolean;
  data: {
    demographics: any;
    labs: any[];
    interpretation: any;
    aggregated: any;
    keyFlags: any[];
    labSetId?: string;
  };
  stored?: boolean;
  message: string;
}

export async function POST(request: NextRequest): Promise<NextResponse> {
